 1	import React, { FC } from 'react';
 2	
 3	import {
 4	  V1VirtualMachine,
 5	  V1VirtualMachineInstanceGuestAgentInfo,
 6	} from '@kubevirt-ui/kubevirt-api/kubevirt';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { VirtualizedTable } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Card, CardBody, Divider } from '@patternfly/react-core';
10	import { isRunning } from '@virtualmachines/utils';
11	
12	import useFilesystemListColumns from '../../../configuration/storage/components/hooks/useFilesystemListColumns';
13	
14	import FilesystemRow from './VirtualMachinesOverviewTabFilesystemRow';
15	import FilesystemListTitle from './VirtualMachinesOverviewTabFilesystemTitle';
16	
17	type VirtualMachinesOverviewTabFilesystemProps = {
18	  guestAgentData: V1VirtualMachineInstanceGuestAgentInfo;
19	  guestAgentDataLoaded: boolean;
20	  vm: V1VirtualMachine;
21	};
22	
23	const VirtualMachinesOverviewTabFilesystem: FC<VirtualMachinesOverviewTabFilesystemProps> = ({
24	  guestAgentData,
25	  guestAgentDataLoaded,
26	  vm,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const isVMRunning = isRunning(vm);
30	  const columns = useFilesystemListColumns();
31	  const fileSystems = guestAgentData?.fsInfo?.disks || [];
32	
33	  return (
34	    <Card>
35	      <FilesystemListTitle />
36	      <Divider />
37	      <CardBody isFilled>
38	        <VirtualizedTable
39	          NoDataEmptyMsg={() =>
40	            !guestAgentData && isVMRunning
41	              ? t('Guest agent is required')
42	              : t('VirtualMachine is not running')
43	          }
44	          columns={columns}
45	          data={fileSystems}
46	          loaded={guestAgentDataLoaded}
47	          loadError={null}
48	          Row={FilesystemRow}
49	          unfilteredData={fileSystems}
50	        />
51	      </CardBody>
52	    </Card>
53	  );
54	};
55	
56	export default VirtualMachinesOverviewTabFilesystem;

